import re
import datetime

def smart_sort(data):
    def try_numeric(s):
        try:
            return int(s)
        except ValueError:
            return s

    def try_float(s):
        try:
            return float(s)
        except ValueError:
            return s

    def try_date(s):
        formats = ["%d %B", "%d %b", "%B %d", "%b %d", "%Y-%m-%d", "%m/%d/%Y", "%d/%m/%Y"]
        for fmt in formats:
            try:
                return datetime.datetime.strptime(s, fmt)
            except ValueError:
                pass
        return s

    def convert_to_number(text):
        text = text.lower()
        num_words = {
            "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4,
            "five": 5, "six": 6, "seven": 7, "eight": 8, "nine": 9,
            "ten": 10, "eleven": 11, "twelve": 12, "thirteen": 13,
            "fourteen": 14, "fifteen": 15, "sixteen": 16, "seventeen": 17,
            "eighteen": 18, "nineteen": 19, "twenty": 20, "thirty": 30,
            "forty": 40, "fifty": 50, "sixty": 60, "seventy": 70,
            "eighty": 80, "ninety": 90
        }
        parts = text.split()
        number = 0
        current_number = 0
        for part in parts:
            if part in num_words:
                current_number += num_words[part]
            elif part == "hundred":
                current_number *= 100
            elif part == "thousand":
                number += current_number * 1000
                current_number = 0
            elif part == "million":
                number += current_number * 1000000
                current_number = 0
            else:
                return None  # Not a number word
        number += current_number
        return number

    def smart_key(s):
        parts = re.split('(\d+)', s, flags=re.IGNORECASE)
        key = []
        for part in parts:
            if part.isdigit():
                key.append(int(part))
            else:
                num_word_val = convert_to_number(part)
                if num_word_val is not None:
                    key.append(num_word_val)
                else:
                    date_val = try_date(part)
                    if isinstance(date_val, datetime.datetime):
                        key.append(date_val)
                    else:
                        key.append(part.lower())
        return key

    try:
        return sorted(data, key=smart_key)
    except:
        return sorted(data, key=lambda x: x.lower())

