import re
import datetime

def smart_sort(data):
    """
    Sorts a list of strings intelligently, attempting to detect underlying ordering
    (numerical, date-based, or alphabetical). Defaults to alphabetical if no pattern is found.
    Handles partial matching (e.g., "iPhone 9", "iPhone X", "iPhone 11").
    """

    def try_int(s):
        try:
            return int(s)
        except ValueError:
            return s

    def try_float(s):
        try:
            return float(s)
        except ValueError:
            return s

    def try_date(s):
        date_formats = ["%d %B", "%B %d", "%d %B %Y", "%B %d %Y", "%Y-%m-%d", "%m/%d/%Y", "%d/%m/%Y"]
        for fmt in date_formats:
            try:
                return datetime.datetime.strptime(s, fmt)
            except ValueError:
                pass
        return s

    def extract_sort_key(item):
        parts = re.split(r'(\d+\.?\d*|\s+)', item)  # Split by numbers and spaces
        key = []
        for part in parts:
            if part.strip() == "":
                continue
            num = try_int(part)
            if isinstance(num, int):
                key.append(num)
            else:
                flt = try_float(part)
                if isinstance(flt, float):
                    key.append(flt)
                else:
                    date = try_date(part.strip())
                    if isinstance(date, datetime.datetime):
                        key.append(date)
                    else:
                        key.append(part.lower())  # Case-insensitive alphabetical sort
        return key

    try:
        return sorted(data, key=extract_sort_key)
    except:
        return sorted(data) # Default to alphabetical if any error occurs

import re
import datetime

def smart_sort(data):
    """
    Sorts a list of strings intelligently, handling numeric, date, and mixed cases.

    Args:
        data: A list of strings to sort.

    Returns:
        A new list containing the sorted strings.
    """

    def try_numeric(s):
        try:
            return int(s)
        except ValueError:
            try:
                return float(s)
            except ValueError:
                return None

    def try_date(s):
        date_formats = ["%d %B", "%B %d", "%d %B %Y", "%B %d %Y", "%Y-%m-%d", "%m/%d/%Y", "%d/%m/%Y"]
        for fmt in date_formats:
            try:
                return datetime.datetime.strptime(s, fmt)
            except ValueError:
                pass
        return None

    def extract_sort_key(s):
        parts = re.split(r'(\d+\.?\d*|\b(?:January|February|March|April|May|June|July|August|September|October|November|December)\b|\b\d{1,2}(?:st|nd|rd|th)?\s(?:January|February|March|April|May|June|July|August|September|October|November|December)\b|\b(?:January|February|March|April|May|June|July|August|September|October|November|December)\s\d{1,2}(?:st|nd|rd|th)?\b)', s)
        key = []
        for part in parts:
            if not part:
                continue
            num = try_numeric(part)
            if num is not None:
                key.append(num)
            else:
                date_val = try_date(part)
                if date_val is not None:
                    key.append(date_val)
                else:
                    key.append(part.lower())  # Case-insensitive string comparison
        return key

    def is_sortable(data):
        if not data:
            return False

        first_key = extract_sort_key(data[0])
        if not first_key:
            return False

        data_type = type(first_key[0]) if first_key else None

        for item in data:
            key = extract_sort_key(item)
            if not key:
                return False
            if type(key[0]) != data_type:
                return False

        return True

    if not data:
        return []

    if is_sortable(data):
        return sorted(data, key=extract_sort_key)
    else:
        return sorted(data)  # Default to alphabetical sort

