        try:
            return int(s)
        except ValueError:
            return s

    def try_float(s):
        try:
            return float(s)
        except ValueError:
            return s

    def try_date(s):
        try:
            # Attempt to parse dates in various common formats
            for fmt in ('%d %B %Y', '%d %B', '%B %d %Y', '%B %d', '%Y-%m-%d', '%m/%d/%Y', '%d/%m/%Y'):
                try:
                    return datetime.datetime.strptime(s, fmt)
                except ValueError:
                    pass
            return s  # Return original string if no date format matches
        except Exception:
            return s

    def try_worded_number(s):
        word_to_num = {
            'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
            'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10,
            'eleven': 11, 'twelve': 12, 'thirteen': 13, 'fourteen': 14,
            'fifteen': 15, 'sixteen': 16, 'seventeen': 17, 'eighteen': 18,
            'nineteen': 19, 'twenty': 20, 'thirty': 30, 'forty': 40,
            'fifty': 50, 'sixty': 60, 'seventy': 70, 'eighty': 80,
            'ninety': 90, 'hundred': 100, 'thousand': 1000,
            'million': 1000000, 'billion': 1000000000
        }
        try:
            s = s.lower()
            words = s.split()
            total = 0
            current = 0
            for word in words:
                if word in word_to_num:
                    num = word_to_num[word]
                    if num == 100:
                        current *= num
                    elif num > 100:
                        total += current * num
                        current = 0
                    else:
                        current += num
                else:
                    return s  # Not a valid worded number
            return total + current
        except:
            return s

    def extract_sort_key(s):
