    Returns:
        A list of tuples, where each tuple contains the original string and its
        corresponding sort key.  The list is sorted by the sort key.
    """

    def get_sort_key(s):
        # Numerical pattern
        match = re.search(r'\b(\d+)\b', s)
        if match:
            return int(match.group(1))

        # Roman numeral pattern
        roman_map = {'i': 1, 'ii': 2, 'iii': 3, 'iv': 4, 'v': 5, 'vi': 6, 'vii': 7,
                     'viii': 8, 'ix': 9, 'x': 10, 'xi': 11, 'xii': 12, 'xiii': 13,
                     'xiv': 14, 'xv': 15, 'xvi': 16, 'xvii': 17, 'xviii': 18,
                     'xix': 19, 'xx': 20, 'xxx': 30, 'xl': 40, 'l': 50, 'lx': 60,
                     'lxx': 70, 'lxxx': 80, 'xc': 90, 'c': 100, 'cd': 400, 'd': 500,
                     'cm': 900, 'm': 1000}

        def roman_to_int(roman_num):
            roman_num = roman_num.lower()
            result = 0
            i = 0
            while i < len(roman_num):
                if i + 1 < len(roman_num) and roman_map[roman_num[i]] < roman_map[roman_num[i + 1]]:
                    result += roman_map[roman_num[i + 1]] - roman_map[roman_num[i]]
                    i += 2
                else:
                    result += roman_map[roman_num[i]]
                    i += 1
            return result

        match = re.search(r'\b(i[vx]|vi{0,3}|ix|x[lc]|xl|l[x]{0,3}|xc|c[md]|cd|d[cm]{0,3}|cm|m{0,4})\b', s, re.IGNORECASE)
        if match:
            try:
                return roman_to_int(match.group(1))
            except KeyError:
                pass

        # Month pattern
        month_names = [month.lower() for month in calendar.month_name[1:]]
        match = re.search(r'\b(' + '|'.join(month_names) + r')\b', s.lower())
        if match:
            return month_names.index(match.group(1)) + 1

        # Worded number pattern (limited to a few common cases)
        worded_numbers = {'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
                           'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10,
                           'eleven': 11, 'twelve': 12}
        match = re.search(r'\b(' + '|'.join(worded_numbers.keys()) + r')\b', s.lower())
        if match:
            return worded_numbers[match.group(1)]

        # Default to alphabetical order (case-insensitive)
        return s.lower()

    return sorted([(s, get_sort_key(s)) for s in strings], key=lambda item: item[1])

