def categorize_string(input_string):
    """
    Categorizes a string based on detected patterns (numerical, date-related, etc.)
    and sorts accordingly. Defaults to alphabetical sorting if no pattern is found.

    Args:
        input_string: The string to categorize.

    Returns:
        A tuple: (category_key, input_string) where category_key is used for sorting.
    """

    input_string = input_string.strip()

    # Numerical patterns (e.g., "Octad 9 x", "iPhone ix", "iPhone X", "iPhone eleven")
    numerical_match = re.search(r'\b(one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve|thirteen|fourteen|fifteen|sixteen|seventeen|eighteen|nineteen|twenty|thirty|forty|fifty|sixty|seventy|eighty|ninety|\d+)\b', input_string, re.IGNORECASE)
    if numerical_match:
        number_str = numerical_match.group(1).lower()
        try:
            number = int(number_str)
        except ValueError:
            number_words = {
                'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5, 'six': 6, 'seven': 7, 'eight': 8, 'nine': 9,
                'ten': 10, 'eleven': 11, 'twelve': 12, 'thirteen': 13, 'fourteen': 14, 'fifteen': 15, 'sixteen': 16,
