                'fifty': 50, 'sixty': 60, 'seventy': 70, 'eighty': 80, 'ninety': 90
            }
            number = number_words.get(number_str, float('inf'))  # Default to infinity if not found

        return (number, input_string)

    # Date-related patterns (e.g., "month thirty one Jan", "single February")
    date_match = re.search(r'\b(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\b', input_string, re.IGNORECASE)
